+const std = @import("std");
+const async = @import("async");
+
+test "async module import" {
+    // Test Channel
+    const chan = try async.makeBuffered(u32, std.testing.allocator, 5);
+    defer chan.deinit();
+
+    // Send some values
+    try std.testing.expect(try chan.trySend(1));
+    try std.testing.expect(try chan.trySend(2));
+    try std.testing.expect(try chan.trySend(3));
+
+    // Receive them
+    try std.testing.expectEqual(@as(?u32, 1), chan.tryRecv());
+    try std.testing.expectEqual(@as(?u32, 2), chan.tryRecv());
+    try std.testing.expectEqual(@as(?u32, 3), chan.tryRecv());
+    try std.testing.expectEqual(@as(?u32, null), chan.tryRecv());
+
+    // Test close
+    chan.close();
+    try std.testing.expect(chan.isClosed());
+}
+
+test "thread pool" {
+    const pool = try async.ThreadPool.init(std.testing.allocator, .{ .num_threads = 2 });
+    defer pool.deinit();
+
+    try pool.start();
+
+    var counter = std.atomic.Value(u32).init(0);
+
+    const Ctx = struct {
+        counter: *std.atomic.Value(u32),
+
+        fn run(ptr: *anyopaque) void {
+            const self: *@This() = @ptrCast(@alignCast(ptr));
+            _ = self.counter.fetchAdd(1, .seq_cst);
+        }
+    };
+
+    var ctxs: [5]Ctx = undefined;
+    var tasks: [5]async.ThreadPool.Task = undefined;
+
+    for (&ctxs, &tasks) |*ctx, *task| {
+        ctx.* = Ctx{ .counter = &counter };
+        task.* = async.ThreadPool.Task{
+            .callback = Ctx.run,
+            .data = ctx,
+        };
+        pool.schedule(task);
+    }
+
+    pool.waitIdle();
+    try std.testing.expectEqual(@as(u32, 5), counter.load(.seq_cst));
+}
+
+test "event loop timer" {
+    const loop = try async.EventLoop.init(std.testing.allocator);
+    defer loop.deinit();
+
+    var called = false;
+    const callback = struct {
+        fn cb(data: *anyopaque) void {
+            const ptr: *bool = @ptrCast(@alignCast(data));
+            ptr.* = true;
+        }
+    }.cb;
+
+    try loop.setTimeout(10, callback, &called);
+    loop.run();
+
+    try std.testing.expect(called);
+}
